t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))
    ans = float('inf')
    for c1 in range(3):
        for c2 in range(3):
            total = c1 + c2
            max_c3 = 0
            feasible = True
            for ai in a:
                best = None
                for x1 in range(min(c1, ai) + 1):
                    for x2 in range(min(c2, (ai - x1) // 2 + 1) + 1):
                        rem = ai - x1 - 2*x2
                        if rem >= 0 and rem % 3 == 0:
                            need3 = rem // 3
                            if best is None or need3 < best:
                                best = need3
                if best is None:
                    feasible = False
                    break
                max_c3 = max(max_c3, best)
            if feasible:
                ans = min(ans, total + max_c3)
    print(ans)

